import pytest
from unittest.mock import Mock

def test_memoize_happy_path():
    """Test that memoize caches function results correctly."""
    @memoize
    def add(a, b):
        return a + b

    # First call - should compute
    assert add(2, 3) == 5
    # Second call with same args - should use cache
    assert add(2, 3) == 5

    # Verify different args work
    assert add(5, 7) == 12
    assert add(5, 7) == 12  # cached

def test_memoize_with_different_args():
    """Test that different arguments don't interfere with each other."""
    @memoize
    def multiply(a, b):
        return a * b

    assert multiply(2, 3) == 6
    assert multiply(2, 4) == 8
    assert multiply(3, 4) == 12

    # Verify original calls still work
    assert multiply(2, 3) == 6
    assert multiply(2, 4) == 8

def test_memoize_with_side_effects():
    """Test that side effects only happen once for cached calls."""
    mock = Mock()
    call_count = 0

    @memoize
    def side_effect_func(x):
        nonlocal call_count
        call_count += 1
        mock(x)
        return f"processed_{x}"

    result1 = side_effect_func("test")
    result2 = side_effect_func("test")

    assert result1 == result2
    assert call_count == 1
    mock.assert_called_once_with("test")

def test_memoize_with_mutable_args():
    """Test that mutable arguments are handled correctly (they shouldn't be)."""
    @memoize
    def process_list(lst):
        return sum(lst)

    list1 = [1, 2, 3]
    list2 = [1, 2, 3]

    # These are different objects, so they'll be cached separately
    assert process_list(list1) == 6
    assert process_list(list2) == 6

    # Modify one list - shouldn't affect the other
    list1.append(4)
    assert process_list(list1) == 10
    assert process_list(list2) == 6  # still cached with original value

def test_memoize_with_no_args():
    """Test memoization with no arguments."""
    call_count = 0

    @memoize
    def no_arg_func():
        nonlocal call_count
        call_count += 1
        return 42

    assert no_arg_func() == 42
    assert no_arg_func() == 42
    assert call_count == 1

def test_memoize_with_exception():
    """Test that exceptions aren't cached."""
    @memoize
    def might_fail(x):
        if x == 0:
            raise ValueError("Can't handle zero")
        return x * 2

    with pytest.raises(ValueError):
        might_fail(0)

    # Should be able to call with other values
    assert might_fail(5) == 10

    # Should raise again when called with 0
    with pytest.raises(ValueError):
        might_fail(0)

def test_memoize_with_none_return():
    """Test memoization with None return value."""
    @memoize
    def might_return_none(x):
        return None if x == 0 else x

    assert might_return_none(0) is None
    assert might_return_none(0) is None  # cached
    assert might_return_none(5) == 5

def test_memoize_with_keyword_args():
    """Test that memoize doesn't work with keyword args (current implementation)."""
    @memoize
    def func(a, b):
        return a + b

    # This will fail because the wrapper only handles *args
    with pytest.raises(TypeError):
        func(a=1, b=2)

def test_memoize_with_unhashable_args():
    """Test behavior with unhashable arguments."""
    @memoize
    def func(x):
        return len(x)

    # Lists are unhashable and can't be used as dict keys
    with pytest.raises(TypeError):
        func([1, 2, 3])

